def now_ts() -> int:
    return int(time.time())


def safe_mkdir(path: str):
    os.makedirs(path, exist_ok=True)


def sha256_bytes(b: bytes) -> str:
    h = hashlib.sha256()
    h.update(b)
    return h.hexdigest()


def sha256_file(path: str) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def is_image_filename(name: str) -> bool:
    ext = os.path.splitext(name.lower())[1]
    return ext in ALLOWED_IMAGE_EXTS


def normalize_label(label: str) -> str:
    label = (label or "").strip()
    if not label:
        raise ValueError("label is empty")
    return label


def load_image_to_rgb(image_bytes: bytes) -> Image.Image:
    img = Image.open(io.BytesIO(image_bytes))
    img = img.convert("RGB")
    return img


def save_image(img: Image.Image, out_path: str):
    safe_mkdir(os.path.dirname(out_path))
    img.save(out_path, format="JPEG", quality=95)


def parse_csv_bytes(csv_bytes: bytes) -> pd.DataFrame:
    try:
        return pd.read_csv(io.BytesIO(csv_bytes))
    except Exception:
        return pd.read_csv(io.BytesIO(csv_bytes), sep=";")


def infer_image_bytes_from_row(row: pd.Series) -> Optional[bytes]:
    if "image_bytes_b64" in row and isinstance(row["image_bytes_b64"], str) and row["image_bytes_b64"].strip():
        import base64
        return base64.b64decode(row["image_bytes_b64"])
    if "image_base64" in row and isinstance(row["image_base64"], str) and row["image_base64"].strip():
        import base64
        return base64.b64decode(row["image_base64"])
    return None


def infer_label_from_row(row: pd.Series) -> str:
    for k in ("label", "class", "category", "y"):
        if k in row and isinstance(row[k], str) and row[k].strip():
            return row[k]
        if k in row and not pd.isna(row[k]):
            return str(row[k])
    raise ValueError("CSV row missing label column (expected one of: label, class, category, y)")


def infer_path_from_row(row: pd.Series) -> Optional[str]:
    for k in ("image_path", "path", "filepath", "file", "filename", "image"):
        if k in row and isinstance(row[k], str) and row[k].strip():
            return row[k].strip()
    return None


