def add_example(dataset_id: str, label: str, image_bytes: bytes, source_type: str, meta: Optional[Dict] = None) -> Dict:
    label = normalize_label(label)
    img = load_image_to_rgb(image_bytes)

    ex_id = uuid.uuid4().hex
    ds_dir = os.path.join(IMAGE_STORE_DIR, dataset_id)
    safe_mkdir(ds_dir)
    out_path = os.path.join(ds_dir, f"{ex_id}.jpg")
    save_image(img, out_path)
    digest = sha256_file(out_path)

    conn = _db_connect()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO examples(example_id, dataset_id, label, source_type, image_path, sha256, created_at, meta_json)
        VALUES(?,?,?,?,?,?,?,?)
        """,
        (ex_id, dataset_id, label, source_type, out_path, digest, now_ts(), json.dumps(meta or {})),
    )
    conn.commit()
    conn.close()

    return {
        "example_id": ex_id,
        "dataset_id": dataset_id,
        "label": label,
        "image_path": out_path,
        "sha256": digest,
    }


def add_examples_from_csv(dataset_id: str, csv_bytes: bytes, zip_bytes: Optional[bytes] = None) -> Dict:
    df = parse_csv_bytes(csv_bytes)
    if df.empty:
        raise ValueError("CSV is empty")

    zip_map: Dict[str, bytes] = {}
    if zip_bytes is not None:
        zf = zipfile.ZipFile(io.BytesIO(zip_bytes))
        for info in zf.infolist():
            if info.is_dir():
                continue
            name = info.filename
            base = os.path.basename(name)
            if is_image_filename(base):
                zip_map[name] = zf.read(info)
                zip_map[base] = zip_map[name]

    added = 0
    errors = []
    for idx, row in df.iterrows():
        try:
            label = normalize_label(infer_label_from_row(row))
            img_bytes = infer_image_bytes_from_row(row)
            if img_bytes is None:
                path = infer_path_from_row(row)
                if not path:
                    raise ValueError("Missing image bytes (image_base64/image_bytes_b64) and missing image path column")
                path = path.strip().lstrip("/")

                if path in zip_map:
                    img_bytes = zip_map[path]
                else:
                    base = os.path.basename(path)
                    if base in zip_map:
                        img_bytes = zip_map[base]
                    else:
                        raise ValueError(f"Image referenced in CSV not found in ZIP: {path}")

            meta = {"csv_row_index": int(idx)}
            add_example(dataset_id, label, img_bytes, "csv", meta=meta)
            added += 1
        except Exception as e:
            errors.append({"row": int(idx), "error": str(e)})

    return {"added": added, "failed": len(errors), "errors": errors[:200]}


