@dataclass
class TrainParams:
    img_size: int = DEFAULT_IMG_SIZE
    batch_size: int = BATCH_SIZE
    epochs: int = 5
    learning_rate: float = 1e-3
    val_split: float = 0.15
    test_split: float = 0.0
    seed: int = 42
    base_model: str = "MobileNetV2"
    fine_tune: bool = False
    fine_tune_at: int = 100
    augment: bool = True


def _build_model(num_classes: int, img_size: int, base_model: str, fine_tune: bool, fine_tune_at: int) -> keras.Model:
    input_shape = (img_size, img_size, 3)
    inputs = keras.Input(shape=input_shape)

    x = inputs
    x = layers.Rescaling(1.0 / 255.0)(x)

    if base_model == "MobileNetV2":
        bm = keras.applications.MobileNetV2(
            input_shape=input_shape, include_top=False, weights="imagenet"
        )
        preprocess = keras.applications.mobilenet_v2.preprocess_input
    elif base_model == "EfficientNetB0":
        bm = keras.applications.EfficientNetB0(
            input_shape=input_shape, include_top=False, weights="imagenet"
        )
        preprocess = keras.applications.efficientnet.preprocess_input
    elif base_model == "ResNet50":
        bm = keras.applications.ResNet50(
            input_shape=input_shape, include_top=False, weights="imagenet"
        )
        preprocess = keras.applications.resnet.preprocess_input
    else:
        raise ValueError("Unsupported base_model. Choose: MobileNetV2, EfficientNetB0, ResNet50")

    x = layers.Lambda(preprocess, name="preprocess")(x)

    bm.trainable = False
    x = bm(x, training=False)
    x = layers.GlobalAveragePooling2D()(x)
    x = layers.Dropout(0.2)(x)
    outputs = layers.Dense(num_classes, activation="softmax")(x)
    model = keras.Model(inputs, outputs)

    if fine_tune:
        bm.trainable = True
        if fine_tune_at is not None and fine_tune_at > 0:
            for layer in bm.layers[:fine_tune_at]:
                layer.trainable = False

    return model


def _make_augmenter(img_size: int) -> keras.Sequential:
    return keras.Sequential(
        [
            layers.RandomFlip("horizontal"),
            layers.RandomRotation(0.05),
            layers.RandomZoom(0.1),
            layers.RandomContrast(0.1),
        ],
        name="augment",
    )


def _load_examples_for_training(dataset_id: str) -> Tuple[List[str], List[str]]:
    conn = _db_connect()
    cur = conn.cursor()
    cur.execute(
        "SELECT image_path, label FROM examples WHERE dataset_id=? ORDER BY created_at ASC",
        (dataset_id,),
    )
    rows = cur.fetchall()
    conn.close()
    paths, labels = [], []
    for r in rows:
        p = r["image_path"]
        if p and os.path.exists(p):
            paths.append(p)
            labels.append(r["label"])
    return paths, labels


def _split_indices(n: int, val_split: float, test_split: float, seed: int) -> Tuple[np.ndarray, np.ndarray, np.ndarray]:
    rng = np.random.default_rng(seed)
    idx = np.arange(n)
    rng.shuffle(idx)
    n_test = int(round(n * test_split))
    n_val = int(round(n * val_split))
    n_test = min(n_test, n)
    n_val = min(n_val, n - n_test)
    test_idx = idx[:n_test]
    val_idx = idx[n_test:n_test + n_val]
    train_idx = idx[n_test + n_val:]
    return train_idx, val_idx, test_idx


def _build_tf_dataset(paths: List[str], labels: List[str], class_to_id: Dict[str, int],
                      img_size: int, batch_size: int, training: bool, augment: bool, seed: int) -> tf.data.Dataset:
    path_ds = tf.data.Dataset.from_tensor_slices(paths)
    label_ids = [class_to_id[l] for l in labels]
    label_ds = tf.data.Dataset.from_tensor_slices(label_ids)

    ds = tf.data.Dataset.zip((path_ds, label_ds))

    def _read(path, y):
        img = tf.io.read_file(path)
        img = tf.image.decode_image(img, channels=3, expand_animations=False)
        img = tf.image.resize(img, (img_size, img_size), method=tf.image.ResizeMethod.BILINEAR)
        img = tf.cast(img, tf.float32)
        return img, tf.cast(y, tf.int32)

    ds = ds.map(_read, num_parallel_calls=AUTOTUNE)

    if training:
        ds = ds.shuffle(min(len(paths), 5000), seed=seed, reshuffle_each_iteration=True)

    if training and augment:
        aug = _make_augmenter(img_size)
        ds = ds.map(lambda x, y: (aug(x, training=True), y), num_parallel_calls=AUTOTUNE)

    ds = ds.batch(batch_size).prefetch(AUTOTUNE)
    return ds


def _evaluate_metrics(model: keras.Model, ds: tf.data.Dataset, num_classes: int) -> Dict:
    y_true = []
    y_pred = []
    for xb, yb in ds:
        preds = model.predict(xb, verbose=0)
        y_true.append(yb.numpy())
        y_pred.append(np.argmax(preds, axis=1))
    if not y_true:
        return {}
    y_true = np.concatenate(y_true)
    y_pred = np.concatenate(y_pred)
    acc = float(np.mean(y_true == y_pred))
    cm = np.zeros((num_classes, num_classes), dtype=np.int64)
    for t, p in zip(y_true, y_pred):
        cm[int(t), int(p)] += 1
    return {"accuracy": acc, "confusion_matrix": cm.tolist()}


_training_lock = threading.Lock()


def _create_training_row(dataset_id: str, params: TrainParams) -> str:
    training_id = uuid.uuid4().hex
    conn = _db_connect()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO trainings(training_id, dataset_id, status, created_at, started_at, finished_at, model_dir, metrics_json, error, params_json)
        VALUES(?,?,?,?,?,?,?,?,?,?)
        """,
        (training_id, dataset_id, "queued", now_ts(), None, None, None, None, None, json.dumps(params.__dict__)),
    )
    conn.commit()
    conn.close()
    return training_id


def _update_training(training_id: str, **fields):
    if not fields:
        return
    cols = []
    vals = []
    for k, v in fields.items():
        cols.append(f"{k}=?")
        vals.append(v)
    vals.append(training_id)
    conn = _db_connect()
    cur = conn.cursor()
    cur.execute(f"UPDATE trainings SET {', '.join(cols)} WHERE training_id=?", tuple(vals))
    conn.commit()
    conn.close()


def _set_active_model(training_id: str, model_dir: str):
    conn = _db_connect()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO active_model(key, training_id, model_dir, updated_at)
        VALUES('active',?,?,?)
        ON CONFLICT(key) DO UPDATE SET training_id=excluded.training_id, model_dir=excluded.model_dir, updated_at=excluded.updated_at
        """,
        (training_id, model_dir, now_ts()),
    )
    conn.commit()
    conn.close()


def get_active_model_info() -> Optional[Dict]:
    conn = _db_connect()
    cur = conn.cursor()
    cur.execute("SELECT key, training_id, model_dir, updated_at FROM active_model WHERE key='active'")
    r = cur.fetchone()
    conn.close()
    return dict(r) if r else None


def _train_job(training_id: str, dataset_id: str, params: TrainParams):
    with _training_lock:
        try:
            _update_training(training_id, status="running", started_at=now_ts(), error=None)

            paths, labels = _load_examples_for_training(dataset_id)
            if len(paths) < 2:
                raise RuntimeError("Not enough examples to train. Need at least 2 images.")

            classes = sorted(list(set(labels)))
            if len(classes) < 2:
                raise RuntimeError("Need at least 2 distinct labels/classes to train.")
            class_to_id = {c: i for i, c in enumerate(classes)}
            id_to_class = {i: c for c, i in class_to_id.items()}

            train_idx, val_idx, test_idx = _split_indices(len(paths), params.val_split, params.test_split, params.seed)
            train_paths = [paths[i] for i in train_idx]
            train_labels = [labels[i] for i in train_idx]
            val_paths = [paths[i] for i in val_idx]
            val_labels = [labels[i] for i in val_idx]
            test_paths = [paths[i] for i in test_idx]
            test_labels = [labels[i] for i in test_idx]

            train_ds = _build_tf_dataset(
                train_paths, train_labels, class_to_id,
                params.img_size, params.batch_size, training=True, augment=params.augment, seed=params.seed
            )
            val_ds = None
            if len(val_paths) > 0:
                val_ds = _build_tf_dataset(
                    val_paths, val_labels, class_to_id,
                    params.img_size, params.batch_size, training=False, augment=False, seed=params.seed
                )

            model = _build_model(
                num_classes=len(classes),
                img_size=params.img_size,
                base_model=params.base_model,
                fine_tune=params.fine_tune,
                fine_tune_at=params.fine_tune_at,
            )

            model.compile(
                optimizer=keras.optimizers.Adam(learning_rate=params.learning_rate),
                loss=keras.losses.SparseCategoricalCrossentropy(),
                metrics=[keras.metrics.SparseCategoricalAccuracy(name="acc")],
            )

            callbacks = [
                keras.callbacks.EarlyStopping(monitor="val_acc" if val_ds else "acc", patience=3, restore_best_weights=True),
            ]

            history = model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=params.epochs,
                callbacks=callbacks,
                verbose=1,
            )

            model_dir = os.path.join(MODELS_DIR, f"{dataset_id}", f"{training_id}")
            safe_mkdir(model_dir)

            model_export_dir = os.path.join(model_dir, "savedmodel")
            keras.models.save_model(model, model_export_dir)

            with open(os.path.join(model_dir, "classes.json"), "w", encoding="utf-8") as f:
                json.dump({"classes": classes, "class_to_id": class_to_id, "id_to_class": id_to_class}, f, ensure_ascii=False, indent=2)

            metrics = {
                "dataset_id": dataset_id,
                "num_examples": len(paths),
                "num_classes": len(classes),
                "classes": classes,
                "history": {k: [float(x) for x in v] for k, v in history.history.items()},
            }

            if val_ds:
                metrics["val_eval"] = _evaluate_metrics(model, val_ds, len(classes))
            if len(test_paths) > 0:
                test_ds = _build_tf_dataset(
                    test_paths, test_labels, class_to_id,
                    params.img_size, params.batch_size, training=False, augment=False, seed=params.seed
                )
                metrics["test_eval"] = _evaluate_metrics(model, test_ds, len(classes))

            _update_training(
                training_id,
                status="succeeded",
                finished_at=now_ts(),
                model_dir=model_dir,
                metrics_json=json.dumps(metrics),
                error=None,
            )
            _set_active_model(training_id, model_dir)
        except Exception as e:
            _update_training(training_id, status="failed", finished_at=now_ts(), error=str(e))


def start_training(dataset_id: str, params: TrainParams, background_tasks: BackgroundTasks) -> str:
    training_id = _create_training_row(dataset_id, params)
    background_tasks.add_task(_train_job, training_id, dataset_id, params)
    return training_id


def get_training(training_id: str) -> Optional[Dict]:
    conn = _db_connect()
    cur = conn.cursor()
    cur.execute(
        """
        SELECT training_id, dataset_id, status, created_at, started_at, finished_at, model_dir, metrics_json, error, params_json
        FROM trainings WHERE training_id=?
        """,
        (training_id,),
    )
    r = cur.fetchone()
    conn.close()
    if not r:
        return None
    d = dict(r)
    for k in ("metrics_json", "params_json"):
        try:
            d[k.replace("_json", "")] = json.loads(d.pop(k) or "{}")
        except Exception:
            d[k.replace("_json", "")] = {}
    return d


def list_trainings(dataset_id: Optional[str] = None, limit: int = 50, offset: int = 0) -> List[Dict]:
    conn = _db_connect()
    cur = conn.cursor()
    if dataset_id:
        cur.execute(
            """
            SELECT training_id, dataset_id, status, created_at, started_at, finished_at, model_dir, metrics_json, error, params_json
            FROM trainings WHERE dataset_id=?
            ORDER BY created_at DESC
            LIMIT ? OFFSET ?
            """,
            (dataset_id, limit, offset),
        )
    else:
        cur.execute(
            """
            SELECT training_id, dataset_id, status, created_at, started_at, finished_at, model_dir, metrics_json, error, params_json
            FROM trainings
            ORDER BY created_at DESC
            LIMIT ? OFFSET ?
            """,
            (limit, offset),
        )
    rows = cur.fetchall()
    conn.close()
    out = []
    for r in rows:
        d = dict(r)
        for k in ("metrics_json", "params_json"):
            try:
                d[k.replace("_json", "")] = json.loads(d.pop(k) or "{}")
            except Exception:
                d[k.replace("_json", "")] = {}
        out.append(d)
    return out


# -----------------------------
# Inference
# -----------------------------
_model_cache = {"model_dir": None, "model": None, "classes": None}
_model_cache_lock = threading.Lock()


def _load_model_from_dir(model_dir: str):
    model_path = os.path.join(model_dir, "savedmodel")
    classes_path = os.path.join(model_dir, "classes.json")
    if not os.path.isdir(model_path):
        raise RuntimeError("Model not found on disk")
    model = keras.models.load_model(model_path)
    with open(classes_path, "r", encoding="utf-8") as f:
        meta = json.load(f)
    classes = meta.get("classes", [])
    return model, classes


def get_active_model():
    info = get_active_model_info()
    if not info:
        return None, None, None
    model_dir = info["model_dir"]
    with _model_cache_lock:
        if _model_cache["model_dir"] != model_dir or _model_cache["model"] is None:
            model, classes = _load_model_from_dir(model_dir)
            _model_cache["model_dir"] = model_dir
            _model_cache["model"] = model
            _model_cache["classes"] = classes
        return info, _model_cache["model"], _model_cache["classes"]


def predict_image_bytes(image_bytes: bytes) -> Dict:
    info, model, classes = get_active_model()
    if model is None:
        raise RuntimeError("No active model. Train a model first.")
    img = load_image_to_rgb(image_bytes)
    img = img.resize((DEFAULT_IMG_SIZE, DEFAULT_IMG_SIZE))
    x = np.array(img).astype("float32")[None, ...]
    probs = model.predict(x, verbose=0)[0]
    top_idx = int(np.argmax(probs))
    top_label = classes[top_idx] if classes and 0 <= top_idx < len(classes) else str(top_idx)
    top_prob = float(probs[top_idx])
    topk = np.argsort(-probs)[: min(5, len(probs))]
    topk_list = [{"label": classes[int(i)] if classes else str(int(i)), "prob": float(probs[int(i)])} for i in topk]
    return {
        "active_training_id": info["training_id"] if info else None,
        "label": top_label,
        "prob": top_prob,
        "topk": topk_list,
    }


