@app.post("/datasets/{dataset_id}/train")
def api_train(
    background_tasks: BackgroundTasks,
    dataset_id: str,
    epochs: int = Form(5),
    batch_size: int = Form(BATCH_SIZE),
    img_size: int = Form(DEFAULT_IMG_SIZE),
    learning_rate: float = Form(1e-3),
    val_split: float = Form(0.15),
    test_split: float = Form(0.0),
    seed: int = Form(42),
    base_model: str = Form("MobileNetV2"),
    fine_tune: bool = Form(False),
    fine_tune_at: int = Form(100),
    augment: bool = Form(True),
):
    try:
        params = TrainParams(
            img_size=int(img_size),
            batch_size=int(batch_size),
            epochs=int(epochs),
            learning_rate=float(learning_rate),
            val_split=float(val_split),
            test_split=float(test_split),
            seed=int(seed),
            base_model=str(base_model),
            fine_tune=bool(fine_tune),
            fine_tune_at=int(fine_tune_at),
            augment=bool(augment),
        )
        if params.epochs < 1 or params.epochs > 200:
            raise ValueError("epochs must be between 1 and 200")
        if params.batch_size < 1 or params.batch_size > 512:
            raise ValueError("batch_size must be between 1 and 512")
        if params.img_size < 32 or params.img_size > 1024:
            raise ValueError("img_size must be between 32 and 1024")
        if not (0.0 <= params.val_split < 0.9):
            raise ValueError("val_split must be in [0.0, 0.9)")
        if not (0.0 <= params.test_split < 0.9):
            raise ValueError("test_split must be in [0.0, 0.9)")
        if params.val_split + params.test_split >= 0.95:
            raise ValueError("val_split + test_split must be < 0.95")

        training_id = start_training(dataset_id, params, background_tasks)
        return {"training_id": training_id, "status": "queued"}
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


